532	function useCardRotation(
533	  ref: React.RefObject<HTMLDivElement | null>,
534	  isActive?: boolean,
535	) {
536	  const position = useMotionValue(20);
537	  const rotate = useMotionValue(0);
538	  React.useEffect(() => {
539	    const scrollContainer = document.querySelector('[data-scroll-container]');
540	
541	    if (!scrollContainer) return;
542	    if (!ref.current) return;
543	
544	    let isInViewport = false;
545	
546	    const observer = new IntersectionObserver(
547	      (entries) => {
548	        const entry = entries[0];
549	        if (entry?.isIntersecting) {
550	          isInViewport = true;
551	        } else {
552	          isInViewport = false;
553	        }
554	      },
555	      {
556	        root: scrollContainer,
557	
558	        threshold: 0,
559	      },
560	    );
561	
562	    observer.observe(ref.current!);
563	
564	    const initialCardRect = ref.current?.getBoundingClientRect();
565	
566	    if (!initialCardRect) return;
567	    const bounds = [
568	      initialCardRect.top,
569	      initialCardRect.top + initialCardRect.height,
570	    ];
571	
572	    function onScroll() {
573	      const containerEle = document.querySelector(
574	        '[data-scroll-container]',
575	      ) as HTMLElement;
576	      if (!containerEle) return;
577	      if (!isInViewport) return;
578	      const scrollY = containerEle.scrollTop + containerEle.clientHeight;
579	
580	      const nextPosition = transform(scrollY, bounds, [20, 4]);
581	      const nextRotate = transform(scrollY, bounds, [0, -3]);
582	
583	      position.set(nextPosition);
584	      rotate.set(nextRotate);
585	    }
586	
587	    scrollContainer.addEventListener('scroll', onScroll);
588	    return () => {
589	      observer.disconnect();
590	      scrollContainer.removeEventListener('scroll', onScroll);
591	    };
592	  }, [position, rotate, ref, isActive]);
593	
594	  return {
595	    position,
596	    rotate,
597	  };
598	}
