315	 * decode-rejection cases above (`AssetKey`, `IsoDate`, `HexColour`,
316	 * `ConferenceSlug`) already prove a bad value never produces a branded value;
317	 * these checks pin the *type-level* half of the guarantee so a future change that
318	 * silently drops a brand fails the typecheck (this whole block is a compile-time
319	 * assertion — the `@ts-expect-error` lines fail `tsc` the moment a raw `string`
320	 * becomes assignable to a brand again).
321	 */
322	describe('branded primitives carry their nominal brand', () => {
323	  test('decode/make produce a branded value, and a raw string is not assignable', () => {
324	    // Decoding yields the branded type, assignable to its own brand…
325	    const key: AssetKeyType = AssetKey.make('2026/en/hero.png');
326	    const date: IsoDateType = IsoDate.make('2026-06-10');
327	    const colour: HexColourType = HexColour.make('#D4A24E');
328	    const slug: ConferenceSlugType = ConferenceSlug.make('/2026');
329	    const itemId: ListItemIdType = ListItemId.make('YOQ7GeACwaTCKjY6y3HAV');
330	
331	    // …and erase to their base string at runtime (brands are type-only).
332	    expect(String(key)).toBe('2026/en/hero.png');
333	    expect(String(date)).toBe('2026-06-10');
334	    expect(String(colour)).toBe('#D4A24E');
335	    expect(String(slug)).toBe('/2026');
336	    expect(String(itemId)).toBe('YOQ7GeACwaTCKjY6y3HAV');
337	
338	    // A raw `string` must NOT be assignable where a brand is required: each line
339	    // is a deliberate type error guarded by `@ts-expect-error`, so the typecheck
340	    // fails if branding is ever lost (`prove-it-works` at the type level).
